  const handleSaveServico = async () => {
    const valor = parseServicoValorInput(servicoValorInput)
    if (!servicoForm.nome.trim() || valor < 0 || Number.isNaN(valor)) {
      alert((t as any).preenchaNomeValor || 'Preencha o nome e um valor válido (zero ou maior) para o serviço!')
      return
    }

    createAutoBackupBeforeOperation()

    let updatedServicos: typeof servicos
    let savedServico: typeof servicos[number]
    if (editingServico) {
      savedServico = {
        ...editingServico,
        cod: servicoForm.cod || undefined,
        nome: servicoForm.nome,
        descricao: servicoForm.descricao || undefined,
        valor,
        tipoCobranca: servicoForm.tipoCobranca,
        categoria: servicoForm.categoria
      }
      updatedServicos = servicos.map(s =>
        s.id === editingServico.id
          ? savedServico
          : s
      )
    } else {
      const newServico = {
        id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
        cod: servicoForm.cod || undefined,
        nome: servicoForm.nome,
        descricao: servicoForm.descricao || undefined,
        valor,
        tipoCobranca: servicoForm.tipoCobranca,
        categoria: servicoForm.categoria
      }
      savedServico = newServico
      updatedServicos = [...servicos, newServico]
    }
    setServicos(updatedServicos)

    try {
      await saveData('nonato-servicos', updatedServicos)
    } catch (err) {
      console.error('Erro ao salvar serviços:', err)
      alert((t as any).erroAoSalvarServico || 'Não foi possível salvar. Verifique se o navegador permite armazenamento local (não use modo anônimo sem permissão) ou tente novamente.')
      return
    }

    setServicoForm({
      cod: savedServico.cod || '',
      nome: savedServico.nome,
      descricao: savedServico.descricao || '',
      valor: savedServico.valor,
      tipoCobranca: savedServico.tipoCobranca,
      categoria: savedServico.categoria
    })
    setServicoValorInput(servicoValorToInputString(savedServico.valor))
    setEditingServico(savedServico)
    alert((t as any).servicoSalvo || 'Serviço salvo com sucesso!')
  }

