  const handlePecaDesmontadaImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files
    if (!files || files.length === 0) return

    const newImages: string[] = []
    Array.from(files).forEach((file) => {
      if (file.type.startsWith('image/')) {
        const reader = new FileReader()
        reader.onload = (event) => {
          const result = event.target?.result as string
          newImages.push(result)
          if (newImages.length === Array.from(files).filter(f => f.type.startsWith('image/')).length) {
            setPecaDesmontadaForm({ 
              ...pecaDesmontadaForm, 
              imagens: [...(pecaDesmontadaForm.imagens || []), ...newImages] 
            })
          }
        }
        reader.readAsDataURL(file)
      }
    })
  }

