      idaHora: '',
      idaChegada: '',
      idaDuracao: '',
      horasInicio: '',
      horasFim: '',
      horasDuracao: '',
      retornoSaida: '',
      retornoChegada: '',
      retornoDuracao: '',
      kmIda: '0',
      kmRetorno: '0',
      kmTotal: '',
