    'open-solicitacao-servico-tecnico': 'agenda',
    'open-agenda': 'agenda',
    'open-desmontados': 'desmontados',
    'open-cadastro-servicos': 'cadastroServicos',
    'open-fechamento-relatorios-servicos': 'relatorioServico',
