  const handleBuscarEquipamentoPreCheck = () => {
    if (preCheckBuscaTipo === 'id') {
      if (!preCheckBuscaId.trim()) {
        alert(safeT?.fillAllFields || 'Por favor, preencha o ID do equipamento')
        return
      }
      const equipamento = equipamentos.find((e) => e.id.toLowerCase() === preCheckBuscaId.trim().toLowerCase())
      if (equipamento) {
        setPreCheckEquipamentoSelecionado(equipamento)
        setPreCheckForm({
          data: new Date().toISOString().split('T')[0],
          tecnicoResponsavel: '',
          observacoes: '',
          status: 'pendente'
        })
      } else {
        alert(safeT?.equipamentoNaoEncontrado || 'Equipamento não encontrado')
        setPreCheckEquipamentoSelecionado(null)
      }
    } else {
      if (!preCheckBuscaNumero.trim()) {
        alert(safeT?.fillAllFields || 'Por favor, preencha o número do equipamento')
        return
      }
      const equipamento = equipamentos.find((e) => e.numeroSerie.toLowerCase() === preCheckBuscaNumero.trim().toLowerCase())
      if (equipamento) {
        setPreCheckEquipamentoSelecionado(equipamento)
        setPreCheckForm({
          data: new Date().toISOString().split('T')[0],
          tecnicoResponsavel: '',
          observacoes: '',
          status: 'pendente'
        })
      } else {
        alert(safeT?.equipamentoNaoEncontrado || 'Equipamento não encontrado')
        setPreCheckEquipamentoSelecionado(null)
      }
    }
  }

