            cliente.telefones?.toLowerCase().includes(buscaCliente.toLowerCase()) ||
            cliente.email?.toLowerCase().includes(buscaCliente.toLowerCase()) ||
            cliente.contato?.toLowerCase().includes(buscaCliente.toLowerCase())
