                          e.currentTarget.style.boxShadow = temNovaMensagem ? '0 0 20px rgba(255, 193, 7, 0.5)' : '0 0 20px rgba(0, 255, 100, 0.3)'
                          e.currentTarget.style.transform = 'translateY(-5px)'
